-- ============================================================
-- PARTE 2: ALTER + INSERT tablas restantes
-- ============================================================

-- ALTER labor_agricola (agregar columnas del catálogo)
ALTER TABLE labor_agricola
  ALTER COLUMN fecha DROP NOT NULL,
  ALTER COLUMN seccion_id DROP NOT NULL,
  ALTER COLUMN tipo_labor DROP NOT NULL,
  ADD COLUMN IF NOT EXISTS nombre text,
  ADD COLUMN IF NOT EXISTS activa boolean,
  ADD COLUMN IF NOT EXISTS unidad_extra text,
  ADD COLUMN IF NOT EXISTS secciones_excluidas jsonb,
  ADD COLUMN IF NOT EXISTS num_ciclos integer;

-- ALTER seccion_agricola (agregar minifinca/activa/acres)
ALTER TABLE seccion_agricola
  ALTER COLUMN codigo DROP NOT NULL,
  ADD COLUMN IF NOT EXISTS minifinca text,
  ADD COLUMN IF NOT EXISTS activa boolean,
  ADD COLUMN IF NOT EXISTS acres numeric;

-- ALTER orden_calibre (agregar fecha/semana/sub_basal/apical)
ALTER TABLE orden_calibre
  ALTER COLUMN color_id DROP NOT NULL,
  ALTER COLUMN calibre_code DROP NOT NULL,
  ADD COLUMN IF NOT EXISTS fecha date,
  ADD COLUMN IF NOT EXISTS semana text,
  ADD COLUMN IF NOT EXISTS sub_basal integer,
  ADD COLUMN IF NOT EXISTS apical integer;

-- ALTER perdidas (agregar fecha/color_name/notas/embolse_id)
ALTER TABLE perdidas
  ALTER COLUMN color_id DROP NOT NULL,
  ALTER COLUMN total_embolse DROP NOT NULL,
  ALTER COLUMN cantidad_perdida DROP NOT NULL,
  ADD COLUMN IF NOT EXISTS fecha date,
  ADD COLUMN IF NOT EXISTS color_name text,
  ADD COLUMN IF NOT EXISTS cantidad integer,
  ADD COLUMN IF NOT EXISTS notas text,
  ADD COLUMN IF NOT EXISTS embolse_id uuid;

-- ALTER trenadas (agregar seccion text)
ALTER TABLE trenadas
  ADD COLUMN IF NOT EXISTS seccion text;

-- labor_agricola
ON CONFLICT (id) DO NOTHING;

-- seccion_agricola
ON CONFLICT (id) DO NOTHING;

-- orden_calibre
ON CONFLICT DO NOTHING;

-- perdidas
ON CONFLICT DO NOTHING;

-- trenadas
ON CONFLICT DO NOTHING;

-- registros_labor
ON CONFLICT DO NOTHING;
